# Move api files from root to api/ if needed
for _fname in ("auth.py", "main.py", "store.py"):
    _src = ROOT / _fname
    _dst = ROOT / "api" / _fname
    if _src.exists() and not _dst.exists():
        shutil.move(str(_src), str(_dst))
        print(f"  [mv] {_fname} -> api/{_fname}")

